import loadable from '@loadable/component'
import { CodeType, LinkReferenceType, LinkType } from '@yozora/ast'
import type { Definition, FootnoteDefinition, YastNode } from '@yozora/ast'
import type { CodeRunnerItem, CodeRunnerProps } from '@yozora/react-code'
import CodeRenderer from '@yozora/react-code'
import GraphvizRenderer from '@yozora/react-code-renderer-graphviz'
import YozoraMarkdown, {
  createYozoraNodesRenderer,
} from '@yozora/react-markdown'
import type {
  MarkdownProps,
  PreviewImageApi,
  TokenRendererMap,
} from '@yozora/react-markdown'
import type { Engine } from 'd3-graphviz'
import React from 'react'
import LinkRenderer from './link'
import './style.styl'

const Viewer = loadable(() => import('react-viewer'))

const codeRunners: CodeRunnerItem[] = [
  {
    title: 'graphviz',
    pattern: /^graphviz|dot$/,
    runner: function GraphvizRunner(
      props: CodeRunnerProps,
    ): React.ReactElement {
      const { value, meta = {}, onError } = props
      return (
        <GraphvizRenderer
          code={value}
          engine={meta.engine as Engine}
          onError={onError}
        />
      )
    },
  },
]

export const customRendererMap: Partial<TokenRendererMap> = {
  [CodeType]: function renderCode(code, key, ctx) {
    const { lang, value, meta } = code

    // Remove trailing line endings.
    const formattedValue = value.replace(/[\r\n]*$/, '')
    return (
      <CodeRenderer
        key={key}
        lang={lang}
        value={formattedValue}
        meta={meta}
        runners={codeRunners}
      />
    )
  },
  [LinkType]: function renderLink(link, key, ctx) {
    const { url, title } = link
    return (
      <LinkRenderer key={key} url={url} title={title}>
        {ctx.renderNodes(link.children)}
      </LinkRenderer>
    )
  },
  [LinkReferenceType]: function renderLinkReference(linkReference, key, ctx) {
    const definition: Omit<Definition, 'type'> =
      ctx.getDefinition(linkReference.identifier) ?? ({} as any)
    const { url = '', title } = definition
    return (
      <LinkRenderer key={key} url={url} title={title}>
        {ctx.renderNodes(linkReference.children)}
      </LinkRenderer>
    )
  },
}

export function Markdown(props: MarkdownProps): React.ReactElement {
  const { rendererMap, ...restProps } = props

  return (
    <YozoraMarkdown
      mathjaxSrc="https://cdn.jsdelivr.net/npm/mathjax@2.7.5/MathJax.js?config=TeX-MML-AM_CHTML"
      {...restProps}
      rendererMap={{ ...customRendererMap, ...rendererMap }}
      Viewer={Viewer}
    />
  )
}

export function createMarkdownNodesRenderer(
  definitionMap: Record<string, Definition>,
  footnoteDefinitionMap: Record<string, FootnoteDefinition>,
  rendererMap?: Partial<TokenRendererMap>,
  imageContext?: PreviewImageApi,
): (nodes: YastNode[]) => React.ReactNode[] {
  return createYozoraNodesRenderer(
    definitionMap,
    footnoteDefinitionMap,
    { ...customRendererMap, ...rendererMap },
    imageContext,
  )
}

export default Markdown
