import React from 'react'

export type MagicPanelVisibility = 'navigation' | 'search' | 'about-me' | null

export interface BlogContextData {
  /**
   * Keyword in the searching panel.
   */
  keyword: string
  /**
   * Whether to display the magic-panel, and what should be displayed.
   */
  magicPanelVisibility: MagicPanelVisibility
  /**
   * Update keyword.
   * @param keyword
   */
  setKeyword(keyword: string | ((currentKeyword: string) => string)): void
  /**
   * Update magicPanelVisibility
   * @param panel
   */
  setMagicPanelVisibility(
    visibility:
      | MagicPanelVisibility
      | ((currentVisibility: MagicPanelVisibility) => MagicPanelVisibility),
  ): void
}

export const initialBlogContextData: BlogContextData = {
  keyword: '',
  magicPanelVisibility: null,
  setKeyword: () => {},
  setMagicPanelVisibility: () => {},
}

export const BlogContext: React.Context<BlogContextData> =
  React.createContext<BlogContextData>(initialBlogContextData)

export default BlogContext
